    {
      "text": "不好意思，我想要一杯小杯的拿鐵。",
      "pinyin": "Bù hǎo yì si, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de0 na2 tie3.",
      "translation_en": "Excuse me, I would like a small latte.",
      "translation_ko": "실례합니다, 작은 라떼 한 잔을 원합니다."
    },
    {
      "text": "不好意思，請幫我加珍珠，謝謝。",
      "pinyin": "Bù hǎo yì si, qǐng bāng wǒ jiā zhēn zhū, xiè xiè.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, qing3 bang1 wo3 jia1 zhen1 zhu1, xie4 xie4.",
      "translation_en": "Excuse me, please add boba for me, thank you.",
      "translation_ko": "실례합니다, 타피오카 펄을 추가해 주세요, 감사합니다."
    },
    {
      "text": "不好意思，我要一杯紅茶，半糖，去冰。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi hóng chá, bàn táng, qù bīng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 hong2 cha2, ban4 tang2, qu4 bing1.",
      "translation_en": "Excuse me, I want a black tea, half sugar, no ice.",
      "translation_ko": "실례합니다, 홍차 한 잔, 반당, 얼음 없이 주세요."
    },
    {
      "text": "不好意思，這個價錢是多少？",
      "pinyin": "Bù hǎo yì si, zhè ge jià qián shì duō shǎo?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, zhe4 ge0 jia4 qian2 shi4 duo1 shao3?",
      "translation_en": "Excuse me, how much is this price?",
      "translation_ko": "실례합니다, 이 가격은 얼마인가요?"
    },
    {
      "text": "不好意思，我要內用，麻煩給我一個湯匙。",
      "pinyin": "Bù hǎo yì si, wǒ yào nèi yòng, má fan gěi wǒ yī ge tāng chí.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 nei4 yong4, ma2 fan0 gei3 wo3 yi1 ge0 tang1 chi2.",
      "translation_en": "Excuse me, I'll eat here, please give me a spoon.",
      "translation_ko": "실례합니다, 매장에서 먹겠습니다, 숟가락 하나 주세요."
    },
    {
      "text": "不好意思，請再說一次，我聽不懂。",
      "pinyin": "Bù hǎo yì si, qǐng zài shuō yī cì, wǒ tīng bù dǒng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, qing3 zai4 shuo1 yi1 ci4, wo3 ting1 bu4 dong3.",
      "translation_en": "Excuse me, please say it again, I don't understand.",
      "translation_ko": "실례합니다, 한 번 더 말씀해 주세요, 이해하지 못했습니다."
    },
    {
      "text": "不好意思，我要一杯綠茶，少冰，微糖。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi lǜ chá, shǎo bīng, wēi táng.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 lü4 cha2, shao3 bing1, wei1 tang2.",
      "translation_en": "Excuse me, I want a green tea, less ice, low sugar.",
      "translation_ko": "실례합니다, 녹차 한 잔, 얼음 적게, 당도 낮게 주세요."
    },
    {
      "text": "不好意思，我要外帶，請幫我拿一個袋子。",
      "pinyin": "Bù hǎo yì si, wǒ yào wài dài, qǐng bāng wǒ ná yī ge dài zi.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 wai4 dai4, qing3 bang1 wo3 na2 yi1 ge0 dai4 zi0.",
      "translation_en": "Excuse me, I'll take it to go, please get me a bag.",
      "translation_ko": "실례합니다, 포장하겠습니다, 봉투 하나 가져다 주세요."
    },
    {
      "text": "不好意思，我要一杯豆漿，正常甜，加珍珠。",
      "pinyin": "Bù hǎo yì si, wǒ yào yī bēi dòu jiāng, zhèng cháng tián, jiā zhēn zhū.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 yi1 bei1 dou4 jiang1, zheng4 chang2 tian2, jia1 zhen1 zhu1.",
      "translation_en": "Excuse me, I want a soy milk, regular sweetness, with boba.",
      "translation_ko": "실례합니다, 두유 한 잔, 일반 당도, 타피오카 펄 추가해 주세요."
    },
    {
      "text": "不好意思，我要等我的朋友，等一下再點。",
      "pinyin": "Bù hǎo yì si, wǒ yào děng wǒ de péng yǒu, děng yī xià zài diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, wo3 yao4 deng3 wo3 de0 peng2 you3, deng3 yi1 xia4 zai4 dian3.",
      "translation_en": "Excuse me, I'll wait for my friend, I'll order later.",
      "translation_ko": "실례합니다, 친구를 기다리겠습니다, 잠시 후에 주문하겠습니다."
    }
  ]
